29		function fmtDate(iso: string | null): string {
30			if (!iso) return '—'
31			return new Date(iso).toLocaleString()
32		}
33	
34		function fmtDuration(ms: number | null): string {
35			if (ms == null) return '—'
36			if (ms < 1000) return `${ms}ms`
37			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`
38			const m = Math.floor(ms / 60_000)
39			const s = Math.floor((ms % 60_000) / 1000)
40			return `${m}m ${s}s`
41		}
