43		function layerBadgeClass(layer: string): string {
44			switch (layer) {
45				case 'work':
46					return 'badge-layer-work'
47				case 'try':
48					return 'badge-layer-try'
49				case 'run':
50					return 'badge-layer-run'
51				default:
52					return 'badge-status-neutral'
53			}
54		}
55	
56		function statusBadgeClass(status: string): string {
57			switch (status) {
58				case 'success':
59					return 'badge-status-closed'
60				case 'failure':
61					return 'badge-status-failed'
62				case 'running':
63					return 'badge-status-running'
64				case 'preserved':
65					return 'badge-status-in-progress'
66				default:
67					return 'badge-status-open'
68			}
69		}
